$base = "$env:USERPROFILE\Desktop\AssetManagement"
$enc  = [System.Text.Encoding]::UTF8

$b1 = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes("$base\AssetManagement.Web\Views\OptionalStages\AdminAffairs.cshtml", $b1)
Write-Host "OK: AdminAffairs.cshtml" -ForegroundColor Green

$b2 = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes("$base\AssetManagement.Web\Views\OptionalStages\Marketing.cshtml", $b2)
Write-Host "OK: Marketing.cshtml" -ForegroundColor Green

dotnet build $base 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Build OK!" -ForegroundColor Green }